INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L4_B', 'D3', 4, 'B', 'Teaching / Reversibility', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Write a rule for how to check ANY subtraction problem to make sure the answer is right.''', 'States that adding the answer to the amount taken away must give the starting number.', 'Says ''do it again''.', 'Why does adding it back together prove it''s right?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L4_C', 'D3', 4, 'C', 'Teaching / Reversibility', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Create a puzzle where someone has to figure out what was taken away: I started with 50, now I have 32. What happened?''', 'Creates a missing subtrahend problem.', 'Creates a standard subtraction problem.', 'Is finding the missing piece the same as subtraction?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L1_A', 'D4', 1, 'A', 'Visual array', 'Grid paper or a tray of organized objects (e.g., an egg carton)', NULL, NULL, NULL, NULL, 'Show an array of 4 rows and 6 columns. Ask: ''How can we count these fast without counting by 1s?''', 'Recognizes they can skip count by rows or columns.', 'Counts every single item.', 'What do you notice about the number of rows and the number in each row? Why is that important?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L1_B', 'D4', 1, 'B', 'Visual array', 'Coins or identical small items', NULL, NULL, NULL, NULL, 'Arrange 15 coins into 3 neat rows. Ask: ''Without pointing to every coin, how do we know how many there are?''', 'Notices there are 5 in each row and adds 5+5+5.', 'Breaks the array to count.', 'If we pushed the rows together, would there be the same number?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L1_C', 'D4', 1, 'C', 'Visual array', 'A building with windows, or a drawing of one', NULL, NULL, NULL, NULL, 'Look at a building with windows arranged in a grid (e.g., 3 floors, 4 windows per floor). Ask: ''How many windows are there? Use the floors to help you count.''', 'Uses skip counting to find the total windows.', 'Cannot see the grid structure.', 'Why do windows get placed like that instead of scattered randomly?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L2_A', 'D4', 2, 'A', 'Model translation', NULL, NULL, NULL, NULL, NULL, 'Ask your child to draw a picture for 4 x 6. Watch to ensure they draw equal groups or an array, not just random dots.', 'Accurately translates the expression into equal groups or an area model.', 'Draws random dots or 4 and 6 dots separately.', 'How do you know your drawing is right? Can you check it a different way?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L2_B', 'D4', 2, 'B', 'Model translation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Show me 5 groups of 3 using your fingers or drawings.''', 'Accurately models the groups and counts them.', 'Cannot represent the multiplication.', 'Is 5 groups of 3 the same as 3 groups of 5? How?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L2_C', 'D4', 2, 'C', 'Model translation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Write the math equation for this: 7 bicycles, how many wheels total?''', 'Writes 7 x 2 = 14 and explains why.', 'Cannot translate the real world situation to multiplication.', 'Why didn''t you write 7 + 2?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L3_A', 'D4', 3, 'A', 'Structural property analysis', NULL, NULL, NULL, NULL, NULL, 'Ask: ''If you know 4 x 6 = 24, do you also know 6 x 4? Why? Can you prove it with your drawing?''', 'Rotates the array drawing 90 degrees to prove commutativity.', 'Does not understand that the product is the same.', 'You just showed 4x6 = 6x4. Does that work for subtraction too? (5-3 vs 3-5?)', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L3_B', 'D4', 3, 'B', 'Structural property analysis', NULL, NULL, NULL, NULL, NULL, 'Say: ''A child drew 5 groups of 4 as 5 circles, but one circle only has 3 dots. The answer they got is 19. Is this multiplication?''', 'Explains that multiplication REQUIRES equal groups, so 19 is just addition.', 'Thinks it''s a multiplication error, not a structural failure.', 'What makes multiplication special compared to just adding numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L3_C', 'D4', 3, 'C', 'Structural property analysis', NULL, NULL, NULL, NULL, NULL, 'Show: 3 x 0 = 3. Ask: ''Why is this wrong? What does 3 x 0 mean?''', 'Explains that 3 groups of nothing is nothing.', 'Believes 3 x 0 = 3, confusing it with addition.', 'If I have 0 plates with 3 cookies each, how many cookies do I have?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L4_A', 'D4', 4, 'A', 'Distributive property design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''We don''t know what 7 x 8 is. But we know 5 x 8 and 2 x 8. Can we use those to find 7 x 8? Show me with a drawing.''', 'Breaks a 7x8 array into a 5x8 and a 2x8 array, demonstrating the distributive property conceptually.', 'Cannot relate the two smaller facts to the larger one.', 'Will breaking a big rectangle into smaller ones ALWAYS give you the same total? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L4_B', 'D4', 4, 'B', 'Distributive property design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''How can knowing 10 x 6 help you figure out 9 x 6?''', 'Explains that 9 x 6 is just 10 x 6 minus one group of 6 (60 - 6 = 54).', 'Does not understand the connection.', 'How does the ''10 times'' trick help you with ''9 times'' for any number?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L4_C', 'D4', 4, 'C', 'Distributive property design', NULL, NULL, NULL, NULL, NULL, 'Say: ''Make a hard multiplication problem using 12. Then show me how to solve it by breaking the 12 into a 10 and a 2.''', 'Sets up a problem like 12 x 7, and solves it as (10x7) + (2x7).', 'Fails to distribute the multiplication over addition.', 'Why break it into 10 and 2 instead of 6 and 6?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L1_A', 'D5', 1, 'A', 'Physical manipulation', 'Countable objects (beans, blocks), cups', NULL, NULL, NULL, NULL, 'Your child needs to divide 12 beans equally into 3 cups. Ask them to explain why the groups are equal.', 'Each cup has exactly 4 items AND child uses words like ''same'', ''equal'', ''fair''.', 'Groups are unequal OR learner cannot explain after 2 prompts.', 'Are they equal? How do you know?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L1_B', 'D5', 1, 'B', 'Physical manipulation', '15 small items, 5 plates', NULL, NULL, NULL, NULL, 'Give the child 15 items to share on 5 plates like dealing cards. ''One for you, one for you...'' Tell them to stop when they run out.', 'Deals items one by one until all plates have 3.', 'Puts random amounts on plates until they are gone.', 'Why did you put one on each plate before giving anyone a second one?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L1_C', 'D5', 1, 'C', 'Physical manipulation', '20 identical objects', NULL, NULL, NULL, NULL, 'Say: ''I have 20 objects. I want to make little piles of 4. How many piles can I make?'' (This is quotative division).', 'Makes 5 groups of 4 by pulling 4 away at a time.', 'Gets confused and tries to make 4 groups.', 'How is this different from sharing them into 4 cups?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L2_A', 'D5', 2, 'A', 'Physical manipulation with recording', NULL, NULL, NULL, NULL, NULL, 'Ask your child to divide 13 objects into 4 groups. Ask: ''What about the extra one? Is that fair?''', 'Correct partitioning in 5/5 cases, including articulating remainder as ''leftover''.', 'Tries to cut the object, or ignores the remainder.', 'If we had one more object, could we make the groups fair?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L2_B', 'D5', 2, 'B', 'Physical manipulation with recording', NULL, NULL, NULL, NULL, NULL, 'Have them draw 24 cookies shared among 6 kids. ''Draw circles for kids, put dots for cookies.''', 'Draws 6 circles with 4 dots each.', 'Draws 24 circles.', 'How did you know how many dots to put in each circle without dealing them one by one?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L2_C', 'D5', 2, 'C', 'Physical manipulation with recording', NULL, NULL, NULL, NULL, NULL, 'Ask: ''If I have 16 wheels, how many cars can I build?''', 'Writes 16 ÷ 4 = 4 cars.', 'Adds 16 + 4.', 'Is this finding the number of groups or the size of the group?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L3_A', 'D5', 3, 'A', 'Error detection + comparison', NULL, NULL, NULL, NULL, NULL, 'Set up a wrong partition (e.g., 15 objects in 4 groups: 4, 4, 4, 3). Ask the child to find the mistake and fix it. Also ask: ''Someone says 12 ÷ 3 = 5. Without counting, can you tell if that''s right or wrong? How?''', 'Identifies error, explains reasoning, uses inverse relationship (''3 x 5 = 15, not 12'').', 'Thinks 12 ÷ 3 = 5 because they don''t know multiplication facts.', 'If you know 3 x 4 = 12, what else do you automatically know about dividing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L3_B', 'D5', 3, 'B', 'Error detection + comparison', NULL, NULL, NULL, NULL, NULL, 'Say: ''I shared 10 sweets between 2 children. One got 6, one got 4. Is that division?''', 'Explains that division must be fair/equal, so this is not division.', 'Agrees it''s division because things were split up.', 'What''s the difference between sharing and dividing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L3_C', 'D5', 3, 'C', 'Error detection + comparison', NULL, NULL, NULL, NULL, NULL, 'Show: 14 ÷ 4 = 3 remainder 2. Say: ''Someone else got 14 ÷ 4 = 2 remainder 6. Why is the second one wrong even though 2x4+6=14?''', 'Explains that a remainder cannot be bigger than the divisor (you can make another group of 4).', 'Cannot explain why the remainder is too big.', 'If you are putting things in groups of 4, why can you never have 6 leftover?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L4_A', 'D5', 4, 'A', 'Design + Teaching', NULL, NULL, NULL, NULL, NULL, 'Say: ''Create a sharing problem for your sibling that has a remainder. Make sure it''s fair. Explain your problem and why the answer must be what it is.''', 'Creates a valid division problem, predicts the answer, explains the structure.', 'Creates a problem without a remainder, or one that cannot be solved.', 'Why do some division problems have remainders and some don''t?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L4_B', 'D5', 4, 'B', 'Design + Teaching', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Design a game where players have to divide numbers by 2. What happens if they get an odd number?''', 'Designs a game with a rule for remainders (e.g., skip a turn, save the remainder).', 'Doesn''t understand odd numbers leave remainders when divided by 2.', 'What do we call numbers that can be divided by 2 with no remainder?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L4_C', 'D5', 4, 'C', 'Design + Teaching', NULL, NULL, NULL, NULL, NULL, 'Say: ''Teach me how multiplication and division are opposites. Use 5, 4, and 20.''', 'Explains that 5x4=20, 4x5=20, 20/4=5, 20/5=4 (fact family).', 'Can''t relate the operations.', 'Does division have a commutative property like multiplication (is 20/4 the same as 4/20)?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L1_A', 'D6', 1, 'A', 'Physical movement', 'Tape on floor or drawn chalk line', NULL, NULL, NULL, NULL, 'Draw a line with marks 0 to 10. Ask your child to stand on 3. Then say: ''Walk to 7. How many steps did you take?''', 'Child counts the *steps* (the spaces between numbers), not the tick marks.', 'Child counts the numbers themselves (3, 4, 5, 6, 7 = 5).', 'What''s the difference between counting the marks and counting the jumps? Which one tells you the distance?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L1_B', 'D6', 1, 'B', 'Physical movement', 'A long ruler or tape measure', NULL, NULL, NULL, NULL, 'Show a measuring tape. Ask: ''If a bug walks from the 10cm mark to the 15cm mark, how far did it walk?''', 'Sees the space between 10 and 15 is 5 units.', 'Says 15cm.', 'Does it matter where the bug started?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L1_C', 'D6', 1, 'C', 'Physical movement', 'Floor tiles or paving stones', NULL, NULL, NULL, NULL, 'Have them stand on a tile. Call it ''Tile 0''. Ask: ''Jump 4 tiles forward. Now jump 2 tiles back. Where are you?''', 'Models 4 - 2 = 2 on the physical grid.', 'Gets lost making the jumps.', 'How is jumping forward and backward like math?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L2_A', 'D6', 2, 'A', 'Abstract representation', NULL, NULL, NULL, NULL, NULL, 'Ask your child to place 48 and 60 on a blank line with 50 in the middle. Check if the distance makes sense.', 'Numbers are in the correct order, and the proportional distance is roughly accurate.', 'Places 48 to the right of 50, or puts 60 right next to 50.', 'Why does the spacing between numbers matter? What happens if you make the spaces uneven?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L2_B', 'D6', 2, 'B', 'Abstract representation', NULL, NULL, NULL, NULL, NULL, 'Draw an open number line. Ask: ''Solve 34 + 12 using jumps on this line.''', 'Starts at 34, jumps 10 to 44, jumps 2 to 46.', 'Tries to draw 46 individual tick marks.', 'Why is it better to jump by 10s than by 1s?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L2_C', 'D6', 2, 'C', 'Abstract representation', NULL, NULL, NULL, NULL, NULL, 'Draw a line with marks at 0, 10, 20. Ask them to point to approximately where 17 is.', 'Points closer to 20 than to 10.', 'Points in the exact middle or close to 10.', 'How did you know it was closer to the 20?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L3_A', 'D6', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a number line where the distance from 0 to 10 is the same size as the distance from 10 to 12. Ask: ''What is wrong with this picture?''', 'Recognizes the scale is broken (10 steps shouldn''t take the same space as 2 steps).', 'Thinks it''s fine because the numbers are in order.', 'Why is a broken scale confusing when you try to solve a math problem?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L3_B', 'D6', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show a number line that goes 10, 20, 30, 50, 60. Ask: ''What''s missing and why is that a problem?''', 'Notices 40 is missing, creating a jump of 20 instead of 10.', 'Doesn''t notice the skip.', 'Can a number line skip numbers if the spaces change size?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L3_C', 'D6', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''Someone tried to solve 50 - 20 by jumping forward instead of backward. Does that work?''', 'Understands that distance is distance, so starting at 20 and jumping to 50 gives the same answer (30).', 'Thinks subtraction MUST move left.', 'Is ''taking away'' the only way to subtract?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L4_A', 'D6', 4, 'A', 'System creation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Design a number line that only shows multiples of 5 (0, 5, 10...). Use it to show someone how to solve 15 + 10.''', 'Creates a consistent scale stepping by 5s and models an operation on it.', 'Draws a line with 1s but only labels the 5s.', 'How does changing the scale (what each tick mark means) make math easier for big numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L4_B', 'D6', 4, 'B', 'System creation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Draw a number line that goes backward, starting at 100 and ending at 0. Use it to solve 80 - 15.''', 'Draws the line correctly with 100 on the left and 0 on the right (unconventional but valid).', 'Cannot conceptualize a reversed line.', 'Does math still work if the line goes the other way? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L4_C', 'D6', 4, 'C', 'System creation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Create a thermometer using a number line. Make sure it has numbers below zero.''', 'Extends the number line to the left of zero with negative numbers.', 'Stops at zero.', 'What do the numbers on the other side of zero mean?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L1_A', 'D7', 1, 'A', 'Observation', '3 rocks, 4 leaves', NULL, NULL, NULL, NULL, 'Show 3 rocks and 4 leaves. Count them (7). Now swap them: show 4 leaves and 3 rocks. Count them. Ask: ''Did the total change? Does the order matter?''', 'Recognizes order doesn''t change the sum (Commutative property).', 'Thinks the new order makes a new amount.', 'If we had 100 rocks and 2 leaves, which is easier to start counting from?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L1_B', 'D7', 1, 'B', 'Observation', '3 types of objects (e.g. 2 spoons, 3 forks, 4 cups)', NULL, NULL, NULL, NULL, 'Put 2 spoons and 3 forks in one group, 4 cups in another. Count total. Then put 2 spoons alone, and 3 forks + 4 cups together. Count total. Ask: ''Did the total change?''', 'Notices grouping differently doesn''t change the sum (Associative property).', 'Believes moving the items changes the total.', 'Does it matter who is grouped with who, if they all go in the same pot?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L1_C', 'D7', 1, 'C', 'Observation', 'Blocks or legos', NULL, NULL, NULL, NULL, 'Build a 2x5 rectangle of blocks. Ask how many. Then turn it 90 degrees to be 5x2. Ask how many. ''Did I add any blocks? Did the total change?''', 'Sees that 2x5 is the same amount as 5x2.', 'Has to recount the blocks when it turns.', 'Does standing a rectangle up make it bigger than laying it down?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L2_A', 'D7', 2, 'A', 'Relational thinking', NULL, NULL, NULL, NULL, NULL, 'Give your child the problem 2 + 7 + 8. Ask: ''Which two numbers should you add first to be fast?''', 'Uses properties (associative/commutative) to group 2+8=10, then add 7 to get 17.', 'Works left to right (2+7=9, 9+8=17), missing the structure.', 'Why is finding a 10 always a good first step?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L2_B', 'D7', 2, 'B', 'Relational thinking', NULL, NULL, NULL, NULL, NULL, 'Say: ''I know 8 x 5 is 40. What is 5 x 8?''', 'Answers 40 immediately without calculating.', 'Tries to count by 5s eight times.', 'If you forget what 7 x 3 is, what other problem could you solve to find the answer?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L2_C', 'D7', 2, 'C', 'Relational thinking', NULL, NULL, NULL, NULL, NULL, 'Show the problem (4 + 6) + 5 = 15. Ask: ''If I move the parentheses to 4 + (6 + 5), what will the answer be?''', 'Knows it will still be 15.', 'Calculates 6+5=11, then 11+4=15 to check.', 'Why do parentheses matter in math, and why do they NOT change the answer in addition?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L3_A', 'D7', 3, 'A', 'Boundary testing', NULL, NULL, NULL, NULL, NULL, 'Ask: ''You know 5 + 3 is the same as 3 + 5. Is 5 - 3 the same as 3 - 5? Let''s check with blocks.''', 'Discovers that subtraction is NOT commutative.', 'Assumes the rule applies to everything.', 'Why does order matter when you take away, but not when you put together?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L3_B', 'D7', 3, 'B', 'Boundary testing', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Is 10 ÷ 2 the same as 2 ÷ 10?''', 'Understands that sharing 10 things among 2 people is very different from sharing 2 things among 10 people.', 'Thinks the answer is 5 both ways.', 'Which operation is division like: addition or subtraction? (Order matters for both subtraction and division).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L3_C', 'D7', 3, 'C', 'Boundary testing', NULL, NULL, NULL, NULL, NULL, 'Say: ''Someone wrote: (10 - 5) - 2 = 10 - (5 - 2). Let''s solve both sides. Do they equal the same thing?''', 'Calculates left side as 3, right side as 7. Realizes the associative property does NOT work for subtraction.', 'Assumes they must be equal without checking.', 'Why can''t you just move parentheses around in a subtraction problem?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L4_A', 'D7', 4, 'A', 'Generalization', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Can you write a rule about adding? Something that is ALWAYS true for any numbers you ever find?''', 'States a rule like ''You can always switch the numbers when adding and get the same answer.''', 'Writes a specific math fact like 2+2=4.', 'Can you prove your rule works for a giant number, like 1,000,000 + 1?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L4_B', 'D7', 4, 'B', 'Generalization', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Make up a trick to help a younger kid remember which math signs let you swap the numbers around.''', 'Creates a memory aid distinguishing + and x from - and ÷.', 'Is confused about which operations allow swapping.', 'Why are + and x ''friendly'' to swapping, but - and ÷ aren''t?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L4_C', 'D7', 4, 'C', 'Generalization', NULL, NULL, NULL, NULL, NULL, 'Say: ''Show me why adding zero to a number never changes it, but multiplying a number by zero changes it to zero.''', 'Explains that adding zero means putting nothing in the pile. Multiplying by zero means having NO piles.', 'Mixes up the rules for zero.', 'What is the ''magic number'' you multiply by to keep a number the same? (Identity property of multiplication = 1).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L1_A', 'D8', 1, 'A', 'Physical balance', 'A hanger balance or visual balance scale, identical items', NULL, NULL, NULL, NULL, 'Put 4 identical blocks on the left, 4 on the right. It balances. Add 1 block to the left. Ask: ''What do I have to do to the right to make it balance again?''', 'Understands that whatever happens to one side must happen to the other.', 'Takes a block away from the right.', 'Why does the equal sign mean ''balance'' and not just ''here comes the answer''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L1_B', 'D8', 1, 'B', 'Physical balance', 'Two transparent cups, water', NULL, NULL, NULL, NULL, 'Pour water into two cups so they are exactly even. Say: ''These are equal.'' Take a sip from one cup. Ask: ''Are they still equal? How do I make them equal again?''', 'Says you must take the same size sip from the other cup.', 'Suggests adding water to the first cup (this is correct, but doesn''t show equivalence of action).', 'If I do something to the left side, what is the golden rule for the right side?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L1_C', 'D8', 1, 'C', 'Physical balance', 'Scale, different sized objects', NULL, NULL, NULL, NULL, 'Put a heavy object on the left. Put 5 light objects on the right so it balances. Ask: ''Is 1 heavy thing equal to 5 light things?''', 'Understands that 1 can equal 5 if the total weight is the same.', 'Says it''s not equal because 1 is not the number 5.', 'Can a big number like 10 be equal to a bunch of small numbers? How?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L2_A', 'D8', 2, 'A', 'Symbolic balance', NULL, NULL, NULL, NULL, NULL, 'Write 5 + 4 = 6 + ___. Remind them: ''='' means BALANCE, not ''write the answer here''.', 'Finds the missing number (3) without adding all visible numbers together.', 'Writes 9 or 15 in the blank.', 'How did you figure out the blank without just guessing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L2_B', 'D8', 2, 'B', 'Symbolic balance', NULL, NULL, NULL, NULL, NULL, 'Write 10 = ___ + 4. Ask them to solve it.', 'Understands that the equation can be ''backwards''. Blank is 6.', 'Gets confused because the answer is on the left.', 'Does the = sign care which side the math problem is on?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L2_C', 'D8', 2, 'C', 'Symbolic balance', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Is this true or false? 4 + 4 = 4 + 4''', 'Recognizes it is true because both sides are identical.', 'Says it''s false because there''s no single answer.', 'What about 4 + 4 = 8 + 0? Is that true?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L3_A', 'D8', 3, 'A', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show this: 8 + 4 = 12 + 2 = 14. Ask: ''Your friend wrote this. What did they think the ''='' sign meant? How would you explain they are wrong?''', 'Understands the friend thought ''='' meant ''compute'', creating a run-on equation (8+4 != 14). Fixes it by separating into two equations.', 'Doesn''t see the problem because 12+2 is 14.', 'Can you ever have two ''='' signs in a row like that if the ends don''t match?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L3_B', 'D8', 3, 'B', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Say: ''A student saw 7 + 5 = ___ + 4. They wrote 12 in the blank. Why did they write 12?''', 'Explains that the student just added 7 and 5 and ignored the ''+ 4''.', 'Thinks 12 is correct.', 'If we put 12 in the blank, what is the total on the right side? Does 12 balance 16?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L3_C', 'D8', 3, 'C', 'Error detection', NULL, NULL, NULL, NULL, NULL, 'Show: ___ = 5 + 3. ''Someone says you can''t start with a blank. Are they right?''', 'Explains that an equation is a balance, so you can start with the total.', 'Agrees you can''t start with a blank.', 'If a scale balances, does it matter which side you look at first?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L4_A', 'D8', 4, 'A', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Create the longest balancing equation you can using addition and subtraction. Like 5 + 5 = 12 - 2 = 6 + 4.''', 'Creates a true, multi-term equation demonstrating deep understanding of equivalence.', 'Makes calculation errors or creates a run-on equation.', 'How can you check every part of your long equation to make sure it''s perfect?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L4_B', 'D8', 4, 'B', 'Design', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Write an equation where the answer is 20, but the number 20 is not allowed to be written anywhere.''', 'Writes something like 10 + 10 = 15 + 5.', 'Cannot conceptualize an equation without the final answer written.', 'Why don''t you need to write the answer to show that they are equal?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L4_C', 'D8', 4, 'C', 'Design', NULL, NULL, NULL, NULL, NULL, 'Say: ''Make a puzzle for me like 7 + ___ = 10 + 2. Don''t make it too easy!''', 'Sets up an equivalent expression with one missing variable.', 'Sets up a standard 7 + 2 = ___ problem.', 'What happens if I guess a number that is too big for your puzzle?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L1_A', 'D9', 1, 'A', 'Magnitude guessing', 'A clear jar with items (e.g., beans)', NULL, NULL, NULL, NULL, 'Show the jar. Ask: ''Are there about 10, about 100, or about 1000 in here? Why do you think that?''', 'Picks the right order of magnitude without counting.', 'Insists on opening the jar to count exactly.', 'How does looking at the size of one bean help you guess the total?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L1_B', 'D9', 1, 'B', 'Magnitude guessing', 'A book', NULL, NULL, NULL, NULL, 'Show a thick book. Ask: ''Does this book have about 20 pages, 200 pages, or 2000 pages? Don''t open it.''', 'Guesses reasonably based on thickness.', 'Cannot connect thickness to quantity.', 'If a book had 2000 pages, how heavy would it be?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L1_C', 'D9', 1, 'C', 'Magnitude guessing', 'Outdoors or looking out a window', NULL, NULL, NULL, NULL, 'Point to a large tree. Ask: ''Does that tree have about 50 leaves, 500 leaves, or more than 5000 leaves?''', 'Understands that natural objects often exist in very large, uncountable quantities.', 'Guesses a small number like 50.', 'Why is it impossible to know the exact number? Does it matter?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L2_A', 'D9', 2, 'A', 'Rounding basics', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Is 48 closer to 40 or 50?''', 'Identifies 50 because 8 is closer to the next ten.', 'Guesses randomly.', 'Is your estimate a guess, or did you use a strategy? What''s the difference?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L2_B', 'D9', 2, 'B', 'Rounding basics', NULL, NULL, NULL, NULL, NULL, 'Say: ''I have 52 coins. My friend has 39 coins. About how many do we have together: 80, 90, or 100?''', 'Rounds 52 to 50, 39 to 40. 50+40 = 90.', 'Tries to calculate 52+39 exactly and gets lost.', 'Why is 90 a good enough answer for this question?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L2_C', 'D9', 2, 'C', 'Rounding basics', NULL, NULL, NULL, NULL, NULL, 'Ask: ''If you take 19 away from 82, will the answer be in the 50s, 60s, or 70s?''', 'Uses estimation (80 - 20 = 60) to find the right decade.', 'Calculates exactly.', 'How does knowing the ''tens'' help you check your exact answer later?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L3_A', 'D9', 3, 'A', 'Checking calculations', NULL, NULL, NULL, NULL, NULL, 'Say: ''Someone added 42 + 59 and got 81. Before adding it yourself, how do you know their answer MUST be wrong?''', 'Notes that 40 + 50 is 90, so the answer must be bigger than 90.', 'Must calculate exactly to know it''s wrong.', 'If you know the real answer has to be bigger than 90, why did they get 81? (They didn''t carry the ten).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L3_B', 'D9', 3, 'B', 'Checking calculations', NULL, NULL, NULL, NULL, NULL, 'Show: 83 - 28 = 65. Ask: ''Use estimation to prove if this answer is reasonable.''', 'Estimates 80 - 30 = 50. Since 65 is nowhere near 50, it is unreasonable.', 'Calculates exactly instead of estimating.', 'Why is it a good habit to estimate the answer in your head before you start doing the math on paper?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L3_C', 'D9', 3, 'C', 'Checking calculations', NULL, NULL, NULL, NULL, NULL, 'Say: ''A machine said 102 - 98 = 104. How do you know that''s crazy without calculating?''', 'Recognizes the numbers are very close together, so the difference must be tiny.', 'Cannot explain why it''s wrong conceptually.', 'When numbers are close together on the number line, is the difference big or small?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L4_A', 'D9', 4, 'A', 'Problem generation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Tell me a story where someone SHOULD estimate instead of counting exactly. Why is it better to estimate there?''', 'Identifies real-world situations (e.g., crowds, distant trees) where estimation is preferred or necessary.', 'Gives a situation like paying for groceries where exactness is required.', 'Can you tell me a rule for when estimation is good enough and when you NEED the exact answer?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L4_B', 'D9', 4, 'B', 'Problem generation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Write a math problem where estimating gives you 100, but the exact answer is 92.''', 'Creates a problem like 51 + 41.', 'Cannot reverse engineer a problem from an estimate.', 'Why does 51 + 41 estimate to 100?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L4_C', 'D9', 4, 'C', 'Problem generation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Imagine you are building a bridge. Should you estimate how long it needs to be, or measure exactly? Why?''', 'Explains that some things must be exact because mistakes are dangerous or expensive.', 'Says estimate because it''s faster.', 'If you had to guess the cost of the bridge, would you estimate the cost higher or lower than you think? (Safety margin).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L4_M', 'D1', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Your grandmother asks you to count the chickens on the farm. There are many. She needs to know how many there are so she can tell the vet. How would you count them so you don''t lose track and don''t have to start over?', 'Child proposes grouping by 10s or another systematic method. Reasoning: explains why grouping prevents double-counting.', 'Counts by 1s or proposes random methods.', 'Why does your method work better than just pointing at them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L4_M', 'D2', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Your family is travelling. In the morning, you drove past 28 road signs. After lunch, you drove past 34 more. Grandmother wants to know the total so she can tell a story about it. Figure it out.', 'Child combines the quantities without being told to ''add''. Uses a strategy (make-a-ten, decomposition) and explains why the total must be more than 50.', 'Waits to be told what operation to use.', 'How did you know you needed to put those numbers together?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L4_M', 'D3', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'There were 43 chapatis on the plate this morning. Now there are 17. Your aunt wants to know what happened. Help her figure it out.', 'Child recognises this is a comparison/difference situation. Finds the gap (26). Reasoning: explains that the missing chapatis are the difference between what was there and what''s left.', 'Adds the numbers together.', 'Why did you find the difference instead of adding?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L4_M', 'D4', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'We are planting a garden. We have 6 rows, and each row has space for 8 seedlings. Tendo wants to buy the seedlings at the market. How many should he buy?', 'Child identifies the array/equal groups structure. Calculates 48. Does not need to be told ''multiply''.', 'Adds 6 + 8.', 'How did you know to count by 8s instead of just adding 6 and 8?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L4_M', 'D5', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Nala brought 30 groundnuts to share with her 5 friends (not including herself). She wants everyone to have the same amount. What should she do?', 'Child partitions 30 into 6 equal groups (Nala + 5 friends). Each gets 5. Reasoning: explains why 6 groups, not 5.', 'Divides by 5, forgetting Nala, or doesn''t know to divide.', 'How do you ensure everyone gets a fair share?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L4_M', 'D6', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'The school is at the 15-kilometre marker on the road. The market is at the 42-kilometre marker. Your uncle wants to know how far it is from school to the market.', 'Child finds the distance (27 km) by subtraction or counting up. Reasoning: explains this is a ''how far between'' problem, not ''what is 15 plus 42''.', 'Adds 15 and 42.', 'Why does finding the space between two markers tell you the distance?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L4_M', 'D7', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'You need to count the total legs on 3 tables and 7 chairs. Tables have 4 legs each and chairs have 4 legs each. Amara says you should count the table legs first, then the chair legs. Tendo says just count all the furniture and multiply by 4. Who gets the answer faster? Do they get the same answer?', 'Child recognises the distributive property/commutativity in action. Both methods work. Explains why.', 'Only calculates one way and thinks the other is wrong.', 'Why do both methods give the exact same total?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L4_M', 'D8', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Your mother gave your brother 6 sweets in the morning and 4 at lunch. She gave you some sweets at lunch only. You both have the same total. How many did she give you?', 'Child sets up the balance (6 + 4 = ?). Finds 10. Key reasoning: the child is not looking for ''= means write the answer'' — they are solving for balance.', 'Adds all numbers they hear (6+4+10).', 'How did you know you needed 10 to make it fair?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L4_M', 'D9', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Aunt Prossy says there are about 200 people at the wedding, but Uncle Joseph says there are 500. You look at the crowd. The chairs have 10 rows of 10. Some people are standing. Who do you think is closer to right? Why?', 'Child uses the anchor (100 chairs × occupancy) to estimate. Recognises that 200 is more plausible than 500, given the visible reference point. Does NOT try to count every head.', 'Tries to guess without using the anchor information.', 'How did the rows of chairs help you prove Uncle Joseph wrong?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

