INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L1_A', 'B2', 1, 'A', 'Number riddle (Oral/Physical)', 'A small cup to hide objects', NULL, NULL, NULL, NULL, 'Hide 4 objects under a cup. Show 3 objects outside. Tell your child: ''Altogether, there are 7 objects. How many are hiding?''', 'Child finds the hidden amount without lifting the cup first. Says ''because 4 and 3 make 7''.', 'Child has to lift the cup to count, or guesses randomly.', 'How did you know how many were hiding without looking? What did your brain do?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L1_B', 'B2', 1, 'B', 'Number riddle (Oral/Physical)', 'A piece of cloth to cover items', NULL, NULL, NULL, NULL, 'Show your child 10 coins. Tell them to close their eyes. Hide 6 under the cloth. Let them open their eyes and see 4 left. Ask: ''How many did I hide?''', 'Quickly identifies 6 are hidden based on knowing 10 - 4.', 'Tries to peek or guesses without using the total.', 'How did you figure it out so fast? Could there be any other number under there?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L1_C', 'B2', 1, 'C', 'Number riddle (Oral/Physical)', 'Two hands', NULL, NULL, NULL, NULL, 'Hold 8 beans total. Put some in one hand, some in the other. Show them 5 in one open hand. Keep the other closed. ''I have 8 total. What''s in the closed hand?''', 'Says 3, using addition or subtraction fact families.', 'Must open the hand to count.', 'If I showed you the 3, would you know the other hand had 5 without looking? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L2_A', 'B2', 2, 'A', 'Symbolic representation', NULL, NULL, NULL, NULL, NULL, 'Show your child equations with a missing piece represented by a box (Box - 5 = 12). Ask them to find the box without guessing randomly.', 'Uses inverse operations (e.g., addition to solve subtraction) to find the unknown.', 'Randomly plugs in numbers until one works.', 'Why did you use that operation to find the missing number? Could you have used a different one?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L2_B', 'B2', 2, 'B', 'Symbolic representation', NULL, NULL, NULL, NULL, NULL, 'Give them problems like ''Triangle + 15 = 25''. Ask them to find Triangle.', 'Correctly identifies Triangle is 10 by subtracting 15 from 25.', 'Adds 15 and 25 to get 40.', 'If Triangle + 15 = 25, what does 25 - Triangle equal?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L2_C', 'B2', 2, 'C', 'Symbolic representation', NULL, NULL, NULL, NULL, NULL, 'Present a word problem: ''A tree had some birds. 6 flew away. Now there are 14. How many were there at first?'' Have them write the equation with a blank.', 'Writes ___ - 6 = 14 and solves for 20.', 'Writes 14 - 6 = 8.', 'How does writing an equation with a blank help you see what happened?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L3_A', 'B2', 3, 'A', 'Constraints & Possibilities', NULL, NULL, NULL, NULL, NULL, 'Show: Triangle + Square = 10. Ask: ''If Triangle is 4, what is Square? Can Triangle be 12? Why or why not?''', 'Understands that variables can take different values, but are constrained by the equation (if one goes up, the other must go down to keep the balance of 10).', 'Thinks Triangle and Square must always be the same number, or doesn''t see why 12 is impossible.', 'Why can''t Triangle be 12 if Triangle + Square = 10? What rule is being broken?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L3_B', 'B2', 3, 'B', 'Constraints & Possibilities', NULL, NULL, NULL, NULL, NULL, 'Say: ''Star - Moon = 5. If Star gets bigger, does Moon have to get bigger or smaller to keep the answer 5?''', 'Realizes that if Star goes up, Moon must also go up (e.g., 10-5=5, 20-15=5).', 'Thinks Moon must get smaller to balance it.', 'If Star gets huge, like 100, what does Moon have to be?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L3_C', 'B2', 3, 'C', 'Constraints & Possibilities', NULL, NULL, NULL, NULL, NULL, 'Show: Circle + Circle = 14. Ask: ''Can the first Circle be 8 and the second Circle be 6?''', 'Explains that identical symbols must represent the same number, so it must be 7+7.', 'Thinks 8+6 is fine because it equals 14.', 'Why do mathematicians use the SAME shape if they want the number to be the same?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L4_A', 'B2', 4, 'A', 'Riddle Generation', NULL, NULL, NULL, NULL, NULL, 'Say: ''Write a number riddle for me where I have to figure out a secret number you are thinking of.'' You must use two operations (like add and subtract).', 'Creates a solvable, multi-step riddle (e.g., ''I multiply by 2, then add 1, and get 11. What''s my number?'').', 'Creates a riddle with no answer, or only one step.', 'Is your riddle solvable? How do you know someone can figure it out and not get stuck?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L4_B', 'B2', 4, 'B', 'Riddle Generation', NULL, NULL, NULL, NULL, NULL, 'Ask: ''Make a puzzle with shapes instead of numbers. Make sure I have enough clues to find what every shape is worth.''', 'Designs a logic puzzle (e.g., Triangle+Triangle=10, Triangle+Square=12).', 'Creates a puzzle with missing information (e.g., Star+Moon=20, what are they?).', 'If you only gave me Star + Moon = 20, why wouldn''t I be able to solve it?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L4_C', 'B2', 4, 'C', 'Riddle Generation', NULL, NULL, NULL, NULL, NULL, 'Tell your child: ''I have a magic box. Whatever number goes in, it adds 5. Write an equation with a blank to show how I would get 20 out.''', 'Writes ___ + 5 = 20.', 'Writes 20 + 5 = ___.', 'Why does the blank go at the beginning instead of the end?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B2_L4_M', 'B2', 4, 'M', 'Real-world situation', NULL, NULL, NULL, NULL, NULL, 'Tendo went to the market with some money. He came back with 500 UGX change and he bought groundnuts for 1,500 UGX. How much did he go with?', 'Child recognises this is a missing-start problem (? - 1500 = 500). Finds 2000. Reasoning: explains how they worked backwards.', 'Adds or subtracts randomly without understanding the story.', 'Why did you add the change to what he spent?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L1_A', 'B3', 1, 'A', 'Physical or visual ''machine''', 'A cardboard box with an ''In'' and ''Out'' slot, or drawing', NULL, NULL, NULL, NULL, 'Say: ''This is a magic machine. If I put in 2, it spits out 5. If I put in 4, it spits out 7. What happens if I put in 10?''', 'Discovers the rule is ''+3'' and applies it correctly to 10.', 'Cannot find a consistent rule.', 'How did you figure out the rule? What if I told you the rule was ×2 instead? Would it still work for all the numbers?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, scientific_materials, acceptable_alternatives, risk_level, safety_warning, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('B3_L1_B', 'B3', 1, 'B', 'Physical or visual ''machine''', 'Paper with a drawn machine', NULL, NULL, NULL, NULL, 'Draw a machine. Say: ''I put in 10, out comes 5. I put in 8, out comes 3. What is the machine doing to the numbers?''', 'Identifies the rule as ''subtract 5''.', 'Thinks the rule changes every time.', 'If I put in a 5, what do you think would happen?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);